INSERT INTO birds (name, description, "imageUrl", "conservationStatus", wingspan, weight, "speciesId", "habitatId") VALUES
('Снегирь Московский', 'Снегирь, обитающий в парках Москвы. Зимой часто прилетает к кормушкам. Самцы выделяются ярко-красной грудкой.', '/images/bullfinch.jpg', 'Least Concern', 25.0, 34.0, 1, 1),
('Синица Парковая', 'Большая синица из Нескучного сада. Активная и любопытная, легко привыкает к кормушкам. Жёлтое брюшко с чёрной полосой.', '/images/tit.jpg', 'Least Concern', 24.0, 18.0, 2, 3),
('Голубь Площадной', 'Типичный сизый голубь Красной площади. Один из самых распространённых обитателей городов по всему миру.', '/images/pigeon.jpg', 'Least Concern', 67.0, 350.0, 3, 3),
('Воробей Дворовый', 'Домовый воробей из жилого квартала на Арбате. Держится вблизи человеческого жилья, гнездится под крышами.', '/images/sparrow.jpg', 'Least Concern', 21.0, 30.0, 4, 3),
('Ворона Измайловская', 'Серая ворона из Измайловского парка. Умная и осторожная, способна использовать инструменты для добычи пищи.', '/images/crow.jpg', 'Least Concern', 100.0, 540.0, 5, 1),
('Скворец Весенний', 'Скворец, гнездящийся в скворечнике Ботанического сада. Отличный имитатор звуков, переливчатое оперение.', '/images/starling.jpg', 'Least Concern', 37.0, 75.0, 6, 1),
('Аист Белый', 'Белый аист, обитающий в Калужской области. Крупная перелётная птица, строит массивные гнёзда на крышах и столбах.', '/images/stork.jpg', 'Least Concern', 215.0, 3500.0, 7, 4),
('Кукушка Лесная', 'Обыкновенная кукушка из Битцевского леса. Известна гнездовым паразитизмом — подбрасывает яйца другим птицам.', '/images/cuckoo.jpg', 'Least Concern', 58.0, 120.0, 8, 2),
('Снегирь Подмосковный', 'Снегирь из лесопарка Лосиный Остров. Предпочитает хвойные и смешанные леса, питается семенами и ягодами.', '/images/bullfinch2.jpg', 'Least Concern', 26.0, 36.0, 1, 2),
('Синица Лазоревка', 'Голубая синица из берёзовой рощи. Миниатюрная птица с голубой шапочкой, часто посещает кормушки зимой.', '/images/bluetit.jpg', 'Least Concern', 20.0, 12.0, 2, 1);
